import React, { useState, useEffect } from 'react';
import api from '../api';
import { useToast } from '../ToastContext';

const SPECS = ['All','Internal Medicine','Cardiology','Pediatrics','Dermatology','Neurology','Orthopedics','Gynecology'];
const ALL_DOCTORS = [
  { id:1, name:'Dr. Rashida Khanam', spec:'Internal Medicine', exp:'14 yrs', rating:4.9, rev:312, init:'RK', c:'#0b7c6f', avail:true,  fee:500,  district:'Dhaka' },
  { id:2, name:'Dr. Imran Hossain',  spec:'Cardiology',        exp:'18 yrs', rating:4.8, rev:248, init:'IH', c:'#2563eb', avail:true,  fee:800,  district:'Dhaka' },
  { id:3, name:'Dr. Fahmida Begum',  spec:'Pediatrics',        exp:'11 yrs', rating:4.9, rev:401, init:'FB', c:'#c9913a', avail:true,  fee:400,  district:'Chittagong' },
  { id:4, name:'Dr. Sadia Islam',    spec:'Neurology',         exp:'16 yrs', rating:4.8, rev:227, init:'SI', c:'#9333ea', avail:true,  fee:700,  district:'Sylhet' },
  { id:5, name:'Dr. Tanvir Ahmed',   spec:'Dermatology',       exp:'9 yrs',  rating:4.7, rev:185, init:'TA', c:'#dc2626', avail:false, fee:450,  district:'Rajshahi' },
  { id:6, name:'Dr. Mahbub Rahman',  spec:'Internal Medicine', exp:'12 yrs', rating:4.6, rev:196, init:'MR', c:'#16a34a', avail:true,  fee:500,  district:'Khulna' },
  { id:7, name:'Dr. Nusrat Jahan',   spec:'Gynecology',        exp:'10 yrs', rating:4.8, rev:154, init:'NJ', c:'#db2777', avail:true,  fee:600,  district:'Dhaka' },
  { id:8, name:'Dr. Aminur Rahman',  spec:'Orthopedics',       exp:'20 yrs', rating:4.9, rev:289, init:'AR', c:'#0891b2', avail:false, fee:750,  district:'Dhaka' },
];

export default function DoctorsPage({ onBook, onBack }) {
  const { addToast } = useToast();
  const [spec,    setSpec]    = useState('All');
  const [search,  setSearch]  = useState('');
  const [avail,   setAvail]   = useState(false);
  const [sort,    setSort]    = useState('rating');
  const [doctors, setDoctors] = useState(ALL_DOCTORS);

  useEffect(() => {
    api.getDoctors().then(d => { if(d.doctors?.length) setDoctors(d.doctors); }).catch(()=>{});
  }, []);

  let filtered = doctors.filter(d => {
    if (spec !== 'All' && d.spec !== spec) return false;
    if (avail && !d.avail) return false;
    if (search && !d.name.toLowerCase().includes(search.toLowerCase()) && !d.spec.toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });
  if (sort==='rating') filtered = [...filtered].sort((a,b) => b.rating - a.rating);
  if (sort==='fee')    filtered = [...filtered].sort((a,b) => a.fee - b.fee);
  if (sort==='exp')    filtered = [...filtered].sort((a,b) => parseInt(b.exp) - parseInt(a.exp));

  return (
    <div style={{ minHeight:'100vh', background:'var(--cream)' }}>
      {/* Header */}
      <div style={{ background:'linear-gradient(135deg,var(--teal-dark),var(--teal))',padding:'28px 5%' }}>
        <button style={{ background:'rgba(255,255,255,0.15)',border:'none',color:'#fff',borderRadius:8,padding:'7px 14px',cursor:'pointer',fontFamily:'Plus Jakarta Sans,sans-serif',fontWeight:500,fontSize:'0.84rem',marginBottom:16 }} onClick={onBack}>← Back</button>
        <h1 style={{ fontFamily:'Cormorant Garamond,serif',color:'#fff',fontSize:'2rem',fontWeight:700,marginBottom:6 }}>Find a Doctor</h1>
        <p style={{ color:'rgba(255,255,255,0.75)',fontSize:'0.9rem' }}>Browse {doctors.length} BMDC-verified specialists across Bangladesh</p>
      </div>

      <div style={{ maxWidth:1200, margin:'0 auto', padding:'28px 5%' }}>
        {/* Filters */}
        <div className="card" style={{ padding:'20px 24px', marginBottom:24, display:'flex', gap:16, flexWrap:'wrap', alignItems:'center' }}>
          <input className="form-input" placeholder="🔍  Search doctors, specialties…" value={search} onChange={e=>setSearch(e.target.value)} style={{ flex:'1',minWidth:200 }} />
          <select className="form-input form-select" value={sort} onChange={e=>setSort(e.target.value)} style={{ width:160 }}>
            <option value="rating">Sort: Rating</option>
            <option value="fee">Sort: Fee (Low)</option>
            <option value="exp">Sort: Experience</option>
          </select>
          <label style={{ display:'flex',alignItems:'center',gap:8,cursor:'pointer',fontSize:'0.88rem',fontWeight:500,userSelect:'none' }}>
            <input type="checkbox" checked={avail} onChange={e=>setAvail(e.target.checked)} style={{ width:16,height:16,accentColor:'var(--teal)',cursor:'pointer' }} />
            Available Only
          </label>
        </div>

        {/* Spec tabs */}
        <div style={{ display:'flex',gap:8,flexWrap:'wrap',marginBottom:24 }}>
          {SPECS.map(s => (
            <button key={s} className={`btn btn-sm ${spec===s?'btn-primary':'btn-ghost'}`} onClick={()=>setSpec(s)}>{s}</button>
          ))}
        </div>

        <p style={{ fontSize:'0.84rem',color:'var(--muted)',marginBottom:18 }}>{filtered.length} doctor{filtered.length!==1?'s':''} found</p>

        {/* Grid */}
        <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(295px,1fr))', gap:20 }}>
          {filtered.map(d => (
            <div key={d.id} className="card" style={{ padding:26,display:'flex',flexDirection:'column',transition:'transform 0.2s,box-shadow 0.2s' }}
              onMouseEnter={e=>{e.currentTarget.style.transform='translateY(-5px)';e.currentTarget.style.boxShadow='var(--shadow-md)'}}
              onMouseLeave={e=>{e.currentTarget.style.transform='translateY(0)';e.currentTarget.style.boxShadow='var(--shadow-sm)'}}>
              <div style={{ display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:12 }}>
                <div style={{ width:58,height:58,borderRadius:'50%',background:`linear-gradient(135deg,${d.c},${d.c}99)`,color:'#fff',display:'flex',alignItems:'center',justifyContent:'center',fontWeight:700,fontSize:'1rem' }}>{d.init}</div>
                <span className={`badge badge-${d.avail?'green':'gray'}`}>{d.avail?'● Online':'○ Offline'}</span>
              </div>
              <span className="badge badge-teal" style={{ marginBottom:8,alignSelf:'flex-start' }}>✓ BMDC Verified</span>
              <h3 style={{ fontFamily:'Cormorant Garamond,serif',fontSize:'1.1rem',fontWeight:700,marginBottom:3 }}>{d.name}</h3>
              <p style={{ fontSize:'0.8rem',color:'var(--muted)',marginBottom:8 }}>{d.spec} · {d.exp} · 📍 {d.district}</p>
              <div style={{ display:'flex',alignItems:'center',gap:6,marginBottom:6 }}>
                <span className="stars">{'★'.repeat(5)}</span>
                <b style={{ fontSize:'0.88rem' }}>{d.rating}</b>
                <span style={{ fontSize:'0.76rem',color:'var(--muted)' }}>({d.rev})</span>
              </div>
              <div style={{ fontSize:'0.84rem',color:'var(--teal)',fontWeight:600,marginBottom:14 }}>
                Consultation Fee: ৳{d.fee}
              </div>
              <div style={{ display:'grid',gridTemplateColumns:'1fr 1fr',gap:8,marginTop:'auto' }}>
                <button className="btn btn-ghost btn-sm" onClick={() => addToast(`Viewing Dr. ${d.name}'s profile`,'info')}>View Profile</button>
                <button className={`btn btn-sm ${d.avail?'btn-primary':'btn-ghost'}`} disabled={!d.avail} onClick={() => onBook(d)}>
                  {d.avail ? 'Book Now' : 'Unavailable'}
                </button>
              </div>
            </div>
          ))}
        </div>

        {filtered.length===0 && (
          <div style={{ textAlign:'center',padding:'60px 20px' }}>
            <div style={{ fontSize:48,marginBottom:12 }}>🔍</div>
            <h3 style={{ fontFamily:'Cormorant Garamond,serif',fontSize:'1.4rem',marginBottom:8 }}>No doctors found</h3>
            <p style={{ color:'var(--muted)' }}>Try adjusting your filters or search term.</p>
            <button className="btn btn-outline" style={{ marginTop:16 }} onClick={() => { setSpec('All'); setSearch(''); setAvail(false); }}>Clear Filters</button>
          </div>
        )}
      </div>
    </div>
  );
}
